UPDATE paragraphs SET transcript = 'welkom bij de uitleg van baast of zeven over het belang van fotosynthese in deze baas of leer je op welke manier mensen afhankelijk zijn van fotosynthese voor het verkrijgen van brandstof dan eerst even een begrip dat je tijdelijk moet hebben dus fossiele brandstoffen dat zijn brandstoffen die zijn ontstaan uit dode resten van organismen dan moet jij dus denken aan alle olieproducten als benzine diesel kerosine dat zijn allemaal brandstoffen die je kunt halen uit olie denk daarbij bijvoorbeeld ook aan gas waar heel veel mensen nederland nog op koken denk daarbij bijvoorbeeld ook aan steenkool bruinkool dat wordt heel veel gebruikt voor het opwekken van elektriciteit dus in de fabriek wordt dat verbrand en dat wordt met een proces dan omgezet naar elektriciteit naar dus voor onze elektriciteit zijn er voor een heel groot deel ook afhankelijk van fossiele brandstoffen die fossiele brandstoffen zijn is ontstaan uit dode resten van organismen en die zijn ontstaan om een hele hoge temperatuur en dat moet je zo voorstellen er zijn natuurlijk heel veel organismen geweest gedurende een hele lange periode rond de aarde bestaat al een tijdje en denken bij aan bomen en planten aan dieren die gaan op een gegeven moment dood en die raken soms afgedekt met een laag aarde of zand of andere materialen dan ontstaat een hele hoge temperatuur en druk en daardoor ontstaat in de loop van de tijd uit die dode resten fossiele brandstoffen 7 de hele korte samenvatting van fossiele brandstoffen hoe ze ontstaan die organismen die konden natuurlijk leven uiteindelijk dankzij fotosynthese bij plant is dat heel duidelijke en planten die vangen met behulp van hun bladeren zonlicht op en die kunnen dan met water en koolstofdioxide glucose en zuurstof maken vervolgens leven ook allerlei andere dieren en andere organismen er van die planten door ze bijvoorbeeld te eten en dat betekent dus dat al die organismen konden leven dankzij fotosynthese nou dan ga je dus dood als organismen en dan verander dus gedurende een periode in fossiele brandstof en dat betekent dat hij niet had kunnen ontstaan die fossiele brandstoffen zonder fotosynthese je ziet het ik ook enorme nadelen aan het gebruik van heel veel fossiele brandstoffen precies wat wij nu aan het doen zijn op aarde want ooit zijn die fossiele brandstof ontstaan er doden rest van organismen daarvoor hebben planten uiteindelijk met behulp van fotosynthese heel veel koolstofdioxide uit de lucht gehaald nu zijn we al die koolstofdioxide dus weer de lucht in aan stoppen door het allemaal te verbranden en dat heeft dramatische gevolgen voor het klimaat dat heeft allerlei gevolgen voor de temperatuur op aarde voor het leefgebieden van dieren die verloren gaan met de weer wordt extreem er dus het is echt super super belangrijk dat we hier dus wel iets aan gaan doen omdat als we hiermee doorgaan nog veel grotere problemen hebben dan dat we eigenlijk nu al hebben maar superpositief je waar die we toch wel een beetje dus dat we afhankelijk zijn van fossiele brandstof dat is hier nog een samenvatting en heel veel succes met oefenen en tot de volgende keer' WHERE id = '1-6';